proof_block:
// The previous attempt asserted the antecedent of the ensures-implication
// unconditionally, which Verus cannot prove (those conjuncts are part of
// the obligation, not facts in scope). Instead, guard the proof with an
// `if` that re-states the antecedent: inside the branch, each conjunct
// becomes a hypothesis, so the functional-uniqueness lemma (which
// converts the two `=~=` equations into a single `==`) is applicable.
// Outside the branch, the ensures-implication is vacuously true.
if (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    && post1_self_.wf()
    && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    && post2_self_.wf() {
    lemma_set_view_unique::<A, N>(pre_self_, i, out, post1_self_, post2_self_);
    assert(post1_self_.seq@ =~= post2_self_.seq@);
    assert(post1_self_.seq@ == post2_self_.seq@);
    assert(post1_self_@ == post2_self_@);
}

helper_lemmas:
proof fn lemma_set_view_unique<A, const N: usize>(
    pre_self_: Array<A, N>, i: usize, out: A,
    post1_self_: Array<A, N>, post2_self_: Array<A, N>,
)
    requires
        post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out),
        post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out),
    ensures
        post1_self_.seq@ == post2_self_.seq@,
        post1_self_@ == post2_self_@,
{
    assert(post1_self_.seq@ =~= post2_self_.seq@);
}
